#include <stdio.h>
#include <stdint.h>
#include <string.h>

/*
 * Memory Operations in C
 * Demonstrates: Read (Load), Write (Store), Pointer arithmetic
 * Simulates low-level memory access operations
 */

#define MEMORY_SIZE 256
#define WORD_SIZE 4 // 4 bytes per word

/* Memory structure simulating main RAM */
typedef struct {
 uint8_t data[MEMORY_SIZE];
 int access_count;
} Memory;

/* Initialize memory */
void memory_init(Memory *mem) {
 memset(mem->data, 0, MEMORY_SIZE);
 mem->access_count = 0;
}

/*
 * READ Operation (Load): Load data from memory address
 * Simulates: R ← [LOC]
 */
uint32_t memory_read(Memory *mem, uint32_t address) {
 // Check word alignment
 if (address % WORD_SIZE != 0) {
 printf("Warning: Unaligned access at address %u\n", address);
 }

 if (address >= MEMORY_SIZE) {
 printf("Error: Address out of bounds\n");
 return 0;
 }

 // Read 4 bytes (one word) from memory
 uint32_t value = *((uint32_t *)(&mem->data[address]));
 mem->access_count++;

 return value;
}

/*
 * WRITE Operation (Store): Store data to memory address
 * Simulates: [LOC] ← R
 */
void memory_write(Memory *mem, uint32_t address, uint32_t value) {
 // Check word alignment
 if (address % WORD_SIZE != 0) {
 printf("Warning: Unaligned access at address %u\n", address);
 }

 if (address >= MEMORY_SIZE) {
 printf("Error: Address out of bounds\n");
 return;
 }

 // Write 4 bytes (one word) to memory
 *((uint32_t *)(&mem->data[address])) = value;
 mem->access_count++;
}

/*
 * Demonstrates memory access during instruction execution
 * Simulates: ADD R1, [1000] instruction
 */
void execute_load_add_store(Memory *mem, uint32_t *registers) {
 // Register numbers: R0=0, R1=1, R2=2

 // Step 1: Fetch instruction (from memory at PC)
 // (Simulated - instruction already in registers)

 // Step 2: Operand fetch - READ from memory address 100
 // R1 ← [100]
 registers[1] = memory_read(mem, 100);
 printf("LOAD: R1 ← [100] = %u\n", registers[1]);

 // Step 3: Read second operand from register
 // R2 contains immediate value or from another memory location
 uint32_t operand2 = memory_read(mem, 104);
 printf("LOAD: Operand2 ← [104] = %u\n", operand2);

 // Step 4: Add operation (register-to-register)
 // R0 = R1 + R2
 registers[0] = registers[1] + operand2;
 printf("ADD: R0 ← R1 + R2 = %u\n", registers[0]);

 // Step 5: Store result back to memory (if needed)
 // [108] ← R0
 memory_write(mem, 108, registers[0]);
 printf("STORE: [108] ← R0 = %u\n", registers[0]);
}

int main() {
 Memory main_memory;
 uint32_t registers[8]; // 8 general-purpose registers

 // Initialize
 memory_init(&main_memory);
 memset(registers, 0, sizeof(registers));

 printf("========================================\n");
 printf("MEMORY OPERATIONS IN C\n");
 printf("========================================\n\n");

 /* Write some data to memory */
 printf("1. WRITE OPERATIONS (Store): [LOC] ← R\n");
 printf("----------------------------------------\n");

 memory_write(&main_memory, 100, 25); // [100] = 25
 memory_write(&main_memory, 104, 75); // [104] = 75
 printf("Wrote 25 to address 100\n");
 printf("Wrote 75 to address 104\n\n");

 /* Read data from memory */
 printf("2. READ OPERATIONS (Load): R ← [LOC]\n");
 printf("----------------------------------------\n");

 uint32_t value1 = memory_read(&main_memory, 100);
 uint32_t value2 = memory_read(&main_memory, 104);
 printf("Read from address 100: %u\n", value1);
 printf("Read from address 104: %u\n", value2);

 /* Demonstrate instruction execution with memory */
 printf("\n3. INSTRUCTION EXECUTION\n");
 printf("----------------------------------------\n");
 execute_load_add_store(&main_memory, registers);

 /* Word alignment demonstration */
 printf("\n4. WORD ALIGNMENT DEMONSTRATION\n");
 printf("----------------------------------------\n");

 uint32_t test_addresses[] = {0, 4, 8, 12, 100, 104};
 for (int i = 0; i < 6; i++) {
 uint32_t addr = test_addresses[i];
 char *alignment = (addr % WORD_SIZE == 0) ? "Aligned" : "Unaligned";
 printf("Address %3u: %s (word size = %d)\n", 
 addr, alignment, WORD_SIZE);
 }

 /* Memory access statistics */
 printf("\n5. MEMORY ACCESS STATISTICS\n");
 printf("----------------------------------------\n");
 printf("Total memory accesses: %d\n", main_memory.access_count);
 printf("Estimated access time: %d ns (at 50ns per access)\n", 
 main_memory.access_count * 50);

 return 0;
}
